"use strict";

const express    = require("express");
const sqlite3    = require("sqlite3").verbose();
const jwt        = require("jsonwebtoken");
const cors       = require("cors");
const bodyParser = require("body-parser");
const path       = require("path");

// ─── Configuration ────────────────────────────────────────────────────────────
const PORT          = process.env.PORT || 3001;
const ADMIN_PASS    = process.env.ADMIN_PASS || "2026";
const JWT_SECRET    = process.env.JWT_SECRET || "qamashi_secret_2026_portal_key";
const JWT_EXPIRES   = "8h";           // Token valid for 8 hours
const DB_PATH       = path.join(__dirname, "portal.db");

// ─── App Init ─────────────────────────────────────────────────────────────────
const app = express();

// ─── Middleware ───────────────────────────────────────────────────────────────
app.use(cors({
  origin: "*",
  methods: ["GET", "POST", "PUT", "DELETE", "OPTIONS"],
  allowedHeaders: ["Content-Type", "Authorization"]
}));

// Increase limit for Base64 images (up to 10 MB)
app.use(bodyParser.json({ limit: "10mb" }));
app.use(bodyParser.urlencoded({ extended: true, limit: "10mb" }));

// Serve the frontend from the same directory (optional convenience)
app.use(express.static(path.join(__dirname)));

// ─── SQLite Database ──────────────────────────────────────────────────────────
const db = new sqlite3.Database(DB_PATH, (err) => {
  if (err) {
    console.error("❌  Could not open database:", err.message);
    process.exit(1);
  }
  console.log(`✅  Connected to SQLite database at ${DB_PATH}`);
});

// Enable WAL mode for better concurrent read performance
db.run("PRAGMA journal_mode=WAL");

// Create the news table if it doesn't exist
db.run(`
  CREATE TABLE IF NOT EXISTS news (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    title_uz    TEXT    NOT NULL DEFAULT '',
    title_ru    TEXT    NOT NULL DEFAULT '',
    title_en    TEXT    NOT NULL DEFAULT '',
    desc_uz     TEXT    NOT NULL DEFAULT '',
    desc_ru     TEXT    NOT NULL DEFAULT '',
    desc_en     TEXT    NOT NULL DEFAULT '',
    date        TEXT    NOT NULL,
    image       TEXT    DEFAULT NULL,
    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
  )
`, (err) => {
  if (err) {
    console.error("❌  Could not create table:", err.message);
  } else {
    console.log("✅  News table ready.");
    // Seed with sample data if the table is empty
    seedIfEmpty();
  }
});

