// ─── JWT Middleware ───────────────────────────────────────────────────────────
/**
 * Verifies the JWT token in the Authorization header.
 * Attaches `req.admin = true` if valid.
 */
function requireAuth(req, res, next) {
  const authHeader = req.headers["authorization"];
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return res.status(401).json({ success: false, message: "Unauthorized: No token provided." });
  }

  const token = authHeader.split(" ")[1];
  jwt.verify(token, JWT_SECRET, (err, decoded) => {
    if (err) {
      return res.status(403).json({ success: false, message: "Forbidden: Invalid or expired token." });
    }
    req.admin = decoded.admin;
    next();
  });
}

// ─── Helper: Wrap db.all / db.run in Promises ─────────────────────────────────
const dbAll = (sql, params = []) =>
  new Promise((resolve, reject) =>
    db.all(sql, params, (err, rows) => (err ? reject(err) : resolve(rows)))
  );

const dbRun = (sql, params = []) =>
  new Promise((resolve, reject) =>
    db.run(sql, params, function (err) {
      if (err) reject(err);
      else resolve({ lastID: this.lastID, changes: this.changes });
    })
  );

const dbGet = (sql, params = []) =>
  new Promise((resolve, reject) =>
    db.get(sql, params, (err, row) => (err ? reject(err) : resolve(row)))
  );

// ─── Routes ───────────────────────────────────────────────────────────────────

/**
 * POST /api/login
 * Body: { password: string }
 * Returns: { success, token, message }
 */
app.post("/api/login", (req, res) => {
  const { password } = req.body;

  if (!password) {
    return res.status(400).json({ success: false, message: "Password is required." });
  }

  if (password !== ADMIN_PASS) {
    // Intentionally vague error for security
    return res.status(401).json({ success: false, message: "Invalid credentials." });
  }

  const token = jwt.sign(
    { admin: true, iat: Math.floor(Date.now() / 1000) },
    JWT_SECRET,
    { expiresIn: JWT_EXPIRES }
  );

  return res.json({
    success: true,
    token,
    message: "Login successful."
  });
});

/**
 * GET /api/news
 * Returns all news, newest first.
 */
app.get("/api/news", async (req, res) => {
  try {
    const rows = await dbAll("SELECT * FROM news ORDER BY date DESC, created_at DESC");
    return res.json({ success: true, data: rows });
  } catch (err) {
    console.error("GET /api/news error:", err);
    return res.status(500).json({ success: false, message: "Database error." });
  }
});

/**
 * GET /api/news/:id
 * Returns a single news item by ID.
 */
app.get("/api/news/:id", async (req, res) => {
  const { id } = req.params;
  try {
    const row = await dbGet("SELECT * FROM news WHERE id = ?", [id]);
    if (!row) return res.status(404).json({ success: false, message: "News not found." });
    return res.json({ success: true, data: row });
  } catch (err) {
    console.error("GET /api/news/:id error:", err);
    return res.status(500).json({ success: false, message: "Database error." });
  }
});

/**
 * POST /api/news (Protected)
 * Body: { title_uz, title_ru, title_en, desc_uz, desc_ru, desc_en, date, image? }
 */
app.post("/api/news", requireAuth, async (req, res) => {
  const { title_uz, title_ru, title_en, desc_uz, desc_ru, desc_en, date, image } = req.body;

  // Basic validation
  if (!title_uz && !title_en && !title_ru) {
    return res.status(400).json({ success: false, message: "At least one title is required." });
  }
  if (!date) {
    return res.status(400).json({ success: false, message: "Date is required." });
  }

  try {
    const result = await dbRun(
      `INSERT INTO news (title_uz, title_ru, title_en, desc_uz, desc_ru, desc_en, date, image)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      [title_uz || "", title_ru || "", title_en || "", desc_uz || "", desc_ru || "", desc_en || "", date, image || null]
    );
    const newRow = await dbGet("SELECT * FROM news WHERE id = ?", [result.lastID]);
    return res.status(201).json({ success: true, data: newRow, message: "News created successfully." });
  } catch (err) {
    console.error("POST /api/news error:", err);
    return res.status(500).json({ success: false, message: "Database error." });
  }
});

/**
 * PUT /api/news/:id (Protected)
 * Body: partial news fields to update
 */
app.put("/api/news/:id", requireAuth, async (req, res) => {
  const { id } = req.params;
  const { title_uz, title_ru, title_en, desc_uz, desc_ru, desc_en, date, image } = req.body;

  try {
    const existing = await dbGet("SELECT * FROM news WHERE id = ?", [id]);
    if (!existing) return res.status(404).json({ success: false, message: "News not found." });

    const updated = {
      title_uz: title_uz ?? existing.title_uz,
      title_ru: title_ru ?? existing.title_ru,
      title_en: title_en ?? existing.title_en,
      desc_uz:  desc_uz  ?? existing.desc_uz,
      desc_ru:  desc_ru  ?? existing.desc_ru,
      desc_en:  desc_en  ?? existing.desc_en,
      date:     date     ?? existing.date,
      image:    image !== undefined ? image : existing.image
    };

    await dbRun(
      `UPDATE news SET
        title_uz = ?, title_ru = ?, title_en = ?,
        desc_uz  = ?, desc_ru  = ?, desc_en  = ?,
        date = ?, image = ?
       WHERE id = ?`,
      [updated.title_uz, updated.title_ru, updated.title_en,
       updated.desc_uz,  updated.desc_ru,  updated.desc_en,
       updated.date, updated.image, id]
    );

    const newRow = await dbGet("SELECT * FROM news WHERE id = ?", [id]);
    return res.json({ success: true, data: newRow, message: "News updated successfully." });
  } catch (err) {
    console.error("PUT /api/news/:id error:", err);
    return res.status(500).json({ success: false, message: "Database error." });
  }
});

/**
 * DELETE /api/news/:id (Protected)
 */
app.delete("/api/news/:id", requireAuth, async (req, res) => {
  const { id } = req.params;
  try {
    const existing = await dbGet("SELECT id FROM news WHERE id = ?", [id]);
    if (!existing) return res.status(404).json({ success: false, message: "News not found." });

    await dbRun("DELETE FROM news WHERE id = ?", [id]);
    return res.json({ success: true, message: `News #${id} deleted successfully.` });
  } catch (err) {
    console.error("DELETE /api/news/:id error:", err);
    return res.status(500).json({ success: false, message: "Database error." });
  }
});

// ─── 404 Handler ──────────────────────────────────────────────────────────────
app.use((req, res) => {
  res.status(404).json({ success: false, message: "Endpoint not found." });
});

// ─── Global Error Handler ─────────────────────────────────────────────────────
app.use((err, req, res, next) => {
  console.error("Unhandled error:", err);
  res.status(500).json({ success: false, message: "Internal server error." });
});

// ─── Start Server ─────────────────────────────────────────────────────────────
app.listen(PORT, () => {
  console.log(`
  ╔═══════════════════════════════════════════════╗
  ║       QAMASHI YOSHLAR PORTALI — BACKEND       ║
  ║  Server running at  http://localhost:${PORT}     ║
  ║  Admin password: ${ADMIN_PASS}                         ║
  ╚═══════════════════════════════════════════════╝
  `);
});

// ─── Graceful Shutdown ────────────────────────────────────────────────────────
process.on("SIGINT", () => {
  db.close((err) => {
    if (err) console.error("Error closing DB:", err.message);
    else console.log("\n🔒  Database connection closed. Bye!");
    process.exit(0);
  });
});
